const revTop = new Int32Array(256);
revTop.fill(-1);

for (let i = 0; i < 256; i++) {
  let c = i;
  for (let j = 0; j < 8; j++) {
    c = (c & 1) ? ((0xedb88320 ^ (c >>> 1)) >>> 0) : (c >>> 1);
  }
  table[i] = c >>> 0;
}

for (let i = 0; i < 256; i++) {
  const top = table[i] >>> 24;
  if (revTop[top] !== -1) throw new Error("non-unique reverse table");
  revTop[top] = i;
}

function step(crc, byte) {
  return (table[(crc ^ byte) & 0xff] ^ (crc >>> 8)) >>> 0;
}

function reverseStep(after, byte) {
  const idx = revTop[after >>> 24];
  const shifted = (after ^ table[idx]) >>> 0;
  return (((shifted << 8) >>> 0) | ((idx ^ byte) & 0xff)) >>> 0;
}

function update(crc, bytes) {
  for (let i = 0; i < bytes.length; i++) crc = step(crc, bytes[i]);
  return crc >>> 0;
}

function code4(a, b, c, d) {
  return (((a * ALEN + b) * ALEN + c) * ALEN + d) >>> 0;
}

function decode4(code, out) {
  out[3] = alphabet[code % ALEN]; code = Math.floor(code / ALEN);
  out[2] = alphabet[code % ALEN]; code = Math.floor(code / ALEN);
  out[1] = alphabet[code % ALEN]; code = Math.floor(code / ALEN);
  out[0] = alphabet[code % ALEN];
}

function validate(mid, targetFinal) {
  const full = Buffer.concat([
    Buffer.from("PASSWORD=8XDP5Q2RT9Z", "ascii"),
    mid,
    Buffer.from("W54\n", "ascii"),
  ]);
  return ((update(0xffffffff, full) ^ 0xffffffff) >>> 0) === targetFinal;
}

const prefix = Buffer.from("PASSWORD=8XDP5Q2RT9Z", "ascii");
const targetFinal = 0xb0725dc4 >>> 0;
const targetState = (targetFinal ^ 0xffffffff) >>> 0;
const prefixState = update(0xffffffff, prefix);

const keys = new Uint32Array(HT_SIZE);
const vals = new Uint32Array(HT_SIZE);
keys.fill(EMPTY);

for (let a = 0; a < ALEN; a++) {
  const s1 = step(prefixState, alphabet[a]);
  for (let b = 0; b < ALEN; b++) {
    const s2 = step(s1, alphabet[b]);
    for (let c = 0; c < ALEN; c++) {
      const s3 = step(s2, alphabet[c]);
      for (let d = 0; d < ALEN; d++) {
        const state = step(s3, alphabet[d]);
        let h = Math.imul(state, 2654435761) & (HT_SIZE - 1);
        while (keys[h] !== EMPTY) h = (h + 1) & (HT_SIZE - 1);
        keys[h] = state;
        vals[h] = code4(a, b, c, d);
      }
    }
  }
}

let beforeSuffix = targetState;
const suffix = Buffer.from("W54\n", "ascii");
for (let i = suffix.length - 1; i >= 0; i--) beforeSuffix = reverseStep(beforeSuffix, suffix[i]);

const left = Buffer.alloc(4);
const mid = Buffer.alloc(9);
const results = [];

for (let a = 0; a < ALEN; a++) {
  for (let b = 0; b < ALEN; b++) {
    for (let c = 0; c < ALEN; c++) {
      for (let d = 0; d < ALEN; d++) {
        for (let e = 0; e < ALEN; e++) {
          let needed = beforeSuffix;
          needed = reverseStep(needed, alphabet[e]);
          needed = reverseStep(needed, alphabet[d]);
          needed = reverseStep(needed, alphabet[c]);
          needed = reverseStep(needed, alphabet[b]);
          needed = reverseStep(needed, alphabet[a]);

          let h = Math.imul(needed, 2654435761) & (HT_SIZE - 1);
          while (keys[h] !== EMPTY) {
            if (keys[h] === needed) {
              decode4(vals[h], left);
              left.copy(mid, 0);
              mid[4] = alphabet[a];
              mid[5] = alphabet[b];
              mid[6] = alphabet[c];
              mid[7] = alphabet[d];
              mid[8] = alphabet[e];
              if (validate(mid, targetFinal)) {
                results.push(`8XDP5Q2RT9Z${mid.toString("ascii")}W54`);
              }
            }
            h = (h + 1) & (HT_SIZE - 1);
          }
        }
      }
    }
  }
}

for (const result of results) console.log(result);
